def MCBarrierRangeAccrualEngine(process,
                                traits,
                                timeSteps,
                                timeStepsPerYear,
                                brownianBridge,
                                antitheticVariate,
                                requiredSamples,
                                requiredTolerance,
                                maxSamples,
                                isBiased,
                                seed):
    traits = traits.lower()
    if traits == "pr" or traits == "pseudorandom":
        cls = MCPRBarrierRangeAccrualEngine
    elif traits == "ld" or traits == "lowdiscrepancy":
        cls = MCLDBarrierRangeAccrualEngine
    else:
        raise RuntimeError("unknown MC traits: %s" % traits);
    return cls(process,
               timeSteps,
               timeStepsPerYear,
               brownianBridge,
               antitheticVariate,
               requiredSamples,
               requiredTolerance,
               maxSamples,
               isBiased,
               seed)

